int maxxor(vector<int>& a) {
    int ans = 0, mask = 0;
    for (int i = 31; i >= 0; i--) {
        mask |= (1 << i);
        unordered_set<int> s;
        for (int x : a) s.insert(x & mask);
        int t = ans | (1 << i);
        for (int x : s) if (s.count(x ^ t)) { ans = t; break; }
    }
    return ans;
}

