def maxxor(a):
    ans = 0
    mask = 0
    for i in range(31, -1, -1):
        mask |= 1 << i
        s = {x & mask for x in a}
        t = ans | (1 << i)
        for x in s:
            if (x ^ t) in s:
                ans = t
                break
    return ans

code.C:
int cmp(const void *a, const void *b) { return (*(int*)a - *(int*)b); }

int maxxor(int *a, int n) {
    int ans = 0, mask = 0;
    for (int i = 31; i >= 0; i--) {
        mask |= 1 << i;
        int sz = n, t = ans | (1 << i), ok = 0;
        int *b = malloc(sz * sizeof(int));
        for (int j = 0; j < n; j++) b[j] = a[j] & mask;
        qsort(b, sz, sizeof(int), cmp);
        for (int j = 0; j < sz; j++) {
            int x = b[j] ^ t;
            int *f = bsearch(&x, b, sz, sizeof(int), cmp);
            if (f) { ans = t; ok = 1; break; }
        }
        free(b);
    }
    return ans;
}

code.Java:
static int maxxor(int[] a) {
    long ans = 0, mask = 0;

    for (int i = 31; i >= 0; i--) {
        mask |= (1L << i);
        HashSet<Long> s = new HashSet<>();

        for (int x : a)
            s.add((long)x & mask);

        long candidate = ans | (1L << i);

        for (long x : s) {
            if (s.contains(x ^ candidate)) {
                ans = candidate;
                break;
            }
        }
    }

    return (int) ans;
}

