function maxxor(a) {
    let ans = 0, mask = 0;
    for (let i = 31; i >= 0; i--) {
        mask |= 1 << i;
        const s = new Set(a.map(x => x & mask));
        const t = ans | (1 << i);
        for (const x of s) {
            if (s.has(x ^ t)) { ans = t; break; }
        }
    }
